package dev.detekt.rules.coroutines.utils

import org.jetbrains.kotlin.analysis.api.KaSession
import org.jetbrains.kotlin.analysis.api.types.KaType
import org.jetbrains.kotlin.analysis.api.types.symbol
import org.jetbrains.kotlin.name.CallableId
import org.jetbrains.kotlin.name.ClassId
import org.jetbrains.kotlin.name.FqName
import org.jetbrains.kotlin.name.Name

context(session: KaSession)
internal fun KaType.isCoroutineScope(): Boolean =
    with(session) {
        sequence {
            yield(this@isCoroutineScope)
            yieldAll(this@isCoroutineScope.allSupertypes)
        }
            .mapNotNull { it.symbol?.classId }
            .contains(CoroutineClassIds.CoroutineScope)
    }

context(session: KaSession)
internal fun KaType.isCoroutinesFlow(): Boolean =
    with(session) {
        sequence {
            yield(this@isCoroutinesFlow)
            yieldAll(this@isCoroutinesFlow.allSupertypes)
        }
            .mapNotNull { it.symbol?.classId }
            .contains(CoroutineClassIds.Flow)
    }

internal object CoroutineClassIds {
    val Flow: ClassId = ClassId.fromString("kotlinx/coroutines/flow/Flow")
    val CoroutineScope: ClassId = ClassId.fromString("kotlinx/coroutines/CoroutineScope")
}

internal object CoroutineCallableIds {
    val CoroutineContextCallableId = CallableId(
        packageName = FqName("kotlin.coroutines"),
        callableName = Name.identifier("coroutineContext")
    )
}

package kotlinx.serialization.internal

import kotlinx.serialization.ExperimentalSerializationApi
import kotlinx.serialization.InternalSerializationApi
import kotlinx.serialization.MissingFieldException
import kotlinx.serialization.descriptors.SerialDescriptor

@OptIn(ExperimentalSerializationApi::class)
@InternalSerializationApi
public fun throwMissingFieldException(seen: Int, goldenMask: Int, descriptor: SerialDescriptor) {
    val missingFields = mutableListOf<String>()

    var missingFieldsBits = goldenMask and seen.inv()
    for (i in 0 until 32) {
        if (missingFieldsBits and 1 != 0) {
            missingFields += descriptor.getElementName(i)
        }
        missingFieldsBits = missingFieldsBits ushr 1
    }
    throw MissingFieldException(missingFields, descriptor.serialName)
}

@OptIn(ExperimentalSerializationApi::class)
@InternalSerializationApi
public fun throwArrayMissingFieldException(seenArray: IntArray, goldenMaskArray: IntArray, descriptor: SerialDescriptor) {
    val missingFields = mutableListOf<String>()

    for (maskSlot in goldenMaskArray.indices) {
        var missingFieldsBits = goldenMaskArray[maskSlot] and seenArray[maskSlot].inv()
        if (missingFieldsBits != 0) {
            for (i in 0 until 32) {
                if (missingFieldsBits and 1 != 0) {
                    missingFields += descriptor.getElementName(maskSlot * 32 + i)
                }
                missingFieldsBits = missingFieldsBits ushr 1
            }
        }
    }
    throw MissingFieldException(missingFields, descriptor.serialName)
}

private suspend fun executeResult(
    context: PipelineContext<Unit, PipelineCall>,
    route: RoutingNode,
    parameters: Parameters
) {
    val routingCallPipeline = route.buildPipeline()
    val receivePipeline = merge(
        context.call.request.pipeline,
        routingCallPipeline.receivePipeline
    ) { ApplicationReceivePipeline(developmentMode) }

    val responsePipeline = merge(
        context.call.response.pipeline,
        routingCallPipeline.sendPipeline
    ) { ApplicationSendPipeline(developmentMode) }

    val routingApplicationCall = RoutingPipelineCall(
        context.call,
        route,
        context.coroutineContext,
        receivePipeline,
        responsePipeline,
        parameters
    )
    val routingCall = RoutingCall(routingApplicationCall)
    application.monitor.raise(RoutingCallStarted, routingCall)
    try {
        routingCallPipeline.execute(routingApplicationCall)
        if (!routingApplicationCall.isHandled) {
            routingApplicationCall.response.status()?.let { status ->
                routingApplicationCall.respond(status)
            }
        }
    } catch (cause: Throwable) {
        routingCall.attributes.put(routingCallKey, routingCall)
        throw cause
    } finally {
        application.monitor.raise(RoutingCallFinished, routingCall)
    }
}

package com.apollographql.apollo.compiler.codegen.kotlin.operations

import com.apollographql.apollo.compiler.codegen.kotlin.CgFile
import com.apollographql.apollo.compiler.codegen.kotlin.CgFileBuilder
import com.apollographql.apollo.compiler.codegen.kotlin.KotlinOperationsContext
import com.apollographql.apollo.compiler.codegen.operationName
import com.apollographql.apollo.compiler.codegen.operationResponseFieldsPackageName
import com.apollographql.apollo.compiler.codegen.selections
import com.apollographql.apollo.compiler.ir.IrOperationDefinition
import com.squareup.kotlinpoet.ClassName

internal class OperationSelectionsBuilder(
    val context: KotlinOperationsContext,
    val operation: IrOperationDefinition,
) : CgFileBuilder {
  private val packageName = context.layout.operationResponseFieldsPackageName(operation.normalizedFilePath)
  private val simpleName = context.layout.operationName(operation).selections()

  override fun prepare() {
    context.resolver.registerOperationSelections(
        operation.name,
        ClassName(packageName, simpleName)
    )
  }

  override fun build(): CgFile {
    return CgFile(
        packageName = packageName,
        fileName = simpleName,
        typeSpecs = listOf(
            CompiledSelectionsBuilder(
                context = context,
            ).build(
                selectionSets = operation.selectionSets,
                rootName = simpleName,
            )
        )
    )
  }
}

package io.mockk.impl.verify

import io.mockk.Invocation
import io.mockk.MockKGateway
import io.mockk.MockKGateway.VerificationParameters
import io.mockk.RecordedCall
import io.mockk.impl.log.SafeToString
import io.mockk.impl.stub.StubRepository
import io.mockk.impl.verify.VerificationHelpers.allInvocations
import io.mockk.impl.verify.VerificationHelpers.reportCalls

class AllCallsCallVerifier(
    stubRepo: StubRepository,
    safeToString: SafeToString,
) : UnorderedCallVerifier(stubRepo, safeToString) {
    override fun verify(
        verificationSequence: List<RecordedCall>,
        params: VerificationParameters,
    ): MockKGateway.VerificationResult {
        val result = super.verify(verificationSequence, params)
        if (result.matches) {
            val allInvocations = verificationSequence.allInvocations(stubRepo)
            val nonMatchingInvocations =
                allInvocations
                    .filter { invoke -> doesNotMatchAnyCalls(verificationSequence, invoke) }

            if (nonMatchingInvocations.isNotEmpty()) {
                return MockKGateway.VerificationResult.Failure(
                    safeToString.exec {
                        "some calls were not matched: $nonMatchingInvocations" +
                            reportCalls(
                                verificationSequence,
                                allInvocations,
                            )
                    },
                )
            }
        }
        return result
    }

    private fun doesNotMatchAnyCalls(
        calls: List<RecordedCall>,
        invoke: Invocation,
    ) = !calls.any { call -> call.matcher.match(invoke) }
}

package io.mockk.proxy.jvm

import io.mockk.proxy.Cancelable
import io.mockk.proxy.MockKAgentException
import io.mockk.proxy.MockKAgentLogger
import io.mockk.proxy.MockKConstructorProxyMaker
import io.mockk.proxy.MockKInvocationHandler
import io.mockk.proxy.common.CancelableResult
import io.mockk.proxy.common.transformation.InlineInstrumentation
import io.mockk.proxy.common.transformation.TransformationRequest
import io.mockk.proxy.common.transformation.TransformationType

internal class ConstructorProxyMaker(
    private val log: MockKAgentLogger,
    private val inliner: InlineInstrumentation?,
    private val constructorHandlers: MutableMap<Any, MockKInvocationHandler>,
) : MockKConstructorProxyMaker {
    override fun constructorProxy(
        clazz: Class<*>,
        handler: MockKInvocationHandler,
    ): Cancelable<Class<*>> {
        if (inliner == null) {
            throw MockKAgentException(
                "Failed to create constructor proxy for $clazz.\n" +
                    "Try running VM with MockK Java Agent\n" +
                    "i.e. with -javaagent:mockk-agent.jar option.",
            )
        }

        constructorHandlers[clazz] = handler

        val cancellation =
            inliner.execute(
                TransformationRequest(
                    setOf(clazz),
                    TransformationType.CONSTRUCTOR,
                ),
            )

        return CancelableResult(clazz, cancellation)
            .alsoOnCancel {
                constructorHandlers.remove(clazz)
            }
    }
}

package io.mockk.proxy.jvm

import io.mockk.proxy.Cancelable
import io.mockk.proxy.MockKAgentException
import io.mockk.proxy.MockKAgentLogger
import io.mockk.proxy.MockKInvocationHandler
import io.mockk.proxy.MockKStaticProxyMaker
import io.mockk.proxy.common.CancelableResult
import io.mockk.proxy.common.transformation.InlineInstrumentation
import io.mockk.proxy.common.transformation.TransformationRequest
import io.mockk.proxy.common.transformation.TransformationType

internal class StaticProxyMaker(
    private val log: MockKAgentLogger,
    private val inliner: InlineInstrumentation?,
    private val staticHandlers: MutableMap<Any, MockKInvocationHandler>,
) : MockKStaticProxyMaker {
    override fun staticProxy(
        clazz: Class<*>,
        handler: MockKInvocationHandler,
    ): Cancelable<Class<*>> {
        if (inliner == null) {
            throw MockKAgentException(
                "Failed to create static proxy for $clazz.\n" +
                    "Try running VM with MockK Java Agent\n" +
                    "i.e. with -javaagent:mockk-agent.jar option.",
            )
        }

        log.debug("Transforming $clazz for static method interception")
        val request =
            TransformationRequest(
                setOf(clazz),
                TransformationType.STATIC,
            )

        val cancellation = inliner.execute(request)

        staticHandlers[clazz] = handler

        return CancelableResult(clazz, cancellation)
            .alsoOnCancel {
                staticHandlers.remove(clazz)
            }
    }
}

package buildsrc.convention

import org.gradle.api.tasks.testing.logging.TestLogEvent
import java.time.Duration

plugins {
    base
    id("buildsrc.convention.spotless")
    id("buildsrc.convention.dokka")
}

// Common build config that can be applied to any project. This should typically be language-independent.

if (project != rootProject) {
    group = rootProject.group
    version = rootProject.version
}

tasks.withType<Test>().configureEach {
    timeout.set(Duration.ofMinutes(10))

    testLogging {
        // don't log console output - it's too noisy
        showCauses = false
        showExceptions = false
        showStackTraces = false
        showStandardStreams = false
        events(
            // only log test outcomes
            TestLogEvent.PASSED,
            TestLogEvent.FAILED,
            TestLogEvent.SKIPPED,
            // TestLogEvent.STARTED,
            // TestLogEvent.STANDARD_ERROR,
            // TestLogEvent.STANDARD_OUT,
        )
    }
}

// Enforce reproducible builds: https://docs.gradle.org/current/userguide/working_with_files.html#sec:reproducible_archives
tasks.withType<AbstractArchiveTask>().configureEach {
    isPreserveFileTimestamps = false
    isReproducibleFileOrder = true
}

plugins {
    alias(libs.plugins.kotlin.multiplatform) apply false
    alias(libs.plugins.android.library) apply false
    alias(libs.plugins.buildconfig) apply false
    alias(libs.plugins.binaryCompatibilityValidator)
    alias(libs.plugins.dokka) apply false
    alias(libs.plugins.touchlab.docusaurusosstemplate)
    alias(libs.plugins.mavenPublish) apply false
    alias(libs.plugins.ktlint) apply false
}

apiValidation {
    nonPublicMarkers.add("co.touchlab.kermit.ExperimentalKermitApi")
    ignoredProjects.addAll(
        listOf(
            "stately-collections",
            "stately-common",
            "stately-iso-collections",
            "stately-isolate"
        )
    )
}

val GROUP: String by project
val VERSION_NAME: String by project

allprojects {
    group = GROUP
    version = VERSION_NAME
}

subprojects {
    apply(plugin = "org.jlleitschuh.gradle.ktlint")

    configure<org.jlleitschuh.gradle.ktlint.KtlintExtension> {
        version.set("1.4.0")
        enableExperimentalRules.set(true)
        verbose.set(true)
        filter {
            exclude { it.file.path.contains("build/") }
        }
    }

    afterEvaluate {
        tasks.named("check") {
            dependsOn(tasks.getByName("ktlintCheck"))
        }
    }
}
